import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Tag } from './Tag';
import { Button } from '../Button';
import { Space } from '../Space';

const TYPES = ['primary', 'success', 'info', 'warning', 'danger'] as const;

const meta = {
  title: 'Components/Tag',
  component: Tag,
  tags: ['autodocs'],
  argTypes: {
    type: { control: 'select', options: ['primary', 'success', 'info', 'warning', 'danger'] },
    size: { control: 'inline-radio', options: ['large', 'default', 'small'] },
    effect: { control: 'inline-radio', options: ['dark', 'light', 'plain'] },
    round: { control: 'boolean' },
    closable: { control: 'boolean' },
    hit: { control: 'boolean' },
    color: { control: 'color' },
  },
  args: {
    children: 'Tag',
    type: 'primary',
  },
} satisfies Meta<typeof Tag>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {};

export const Types: Story = {
  render: () => (
    <Space wrap>
      <Tag>Default</Tag>
      {TYPES.map((t) => (
        <Tag key={t} type={t}>
          {t}
        </Tag>
      ))}
    </Space>
  ),
};

export const Effects: Story = {
  render: () => (
    <Space direction="vertical" align="start">
      {(['dark', 'light', 'plain'] as const).map((effect) => (
        <Space key={effect} wrap>
          {TYPES.map((t) => (
            <Tag key={t} type={t} effect={effect}>
              {t}
            </Tag>
          ))}
        </Space>
      ))}
    </Space>
  ),
};

export const SizesAndRound: Story = {
  name: 'Sizes and round',
  render: () => (
    <Space align="center" wrap>
      <Tag type="primary" size="large">
        Large
      </Tag>
      <Tag type="primary">Default</Tag>
      <Tag type="primary" size="small">
        Small
      </Tag>
      <Tag type="primary" round>
        Round
      </Tag>
    </Space>
  ),
};

export const Closable: Story = {
  render: () => {
    const initial = ['Design', 'Tokens', 'React', 'Dark mode'];
    const [tags, setTags] = useState(initial);
    return (
      <Space wrap align="center">
        {tags.map((tag) => (
          <Tag
            key={tag}
            type="primary"
            effect="light"
            closable
            onClose={() => setTags(tags.filter((t) => t !== tag))}
          >
            {tag}
          </Tag>
        ))}
        {tags.length === 0 ? (
          <Button size="small" onClick={() => setTags(initial)}>
            Restore
          </Button>
        ) : null}
      </Space>
    );
  },
};

import {
  type CSSProperties,
  forwardRef,
  type HTMLAttributes,
  type MouseEvent,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type TagType = 'primary' | 'success' | 'info' | 'warning' | 'danger';

export type TagSize = 'large' | 'default' | 'small';

export type TagEffect = 'dark' | 'light' | 'plain';

export interface TagProps extends Omit<HTMLAttributes<HTMLSpanElement>, 'onClick'> {
  /** Visual variant. */
  type?: TagType;
  /** Size. */
  size?: TagSize;
  /** Theme intensity. */
  effect?: TagEffect;
  /** Rounded corners. */
  round?: boolean;
  /** Show a close button. */
  closable?: boolean;
  /** Highlight the border. */
  hit?: boolean;
  /** Custom background color. */
  color?: string;
  /** Disable the appearance transition. */
  disableTransitions?: boolean;
  /** Fired when the close button is clicked. */
  onClose?: (e: MouseEvent) => void;
  /** Fired when the tag body is clicked. */
  onClick?: (e: MouseEvent) => void;
  children?: ReactNode;
}

export const Tag = forwardRef<HTMLSpanElement, TagProps>(function Tag(props, ref) {
  const {
    type = 'primary',
    size = 'default',
    effect = 'light',
    round = false,
    closable = false,
    hit = false,
    color,
    disableTransitions = false,
    onClose,
    onClick,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('tag');

  const classes = cls(
    ns.b(),
    type && ns.m(type),
    size !== 'default' && ns.m(size),
    ns.m(effect),
    ns.is('round', round),
    ns.is('hit', hit),
    ns.is('closable', closable),
    ns.is('disable-transitions', disableTransitions),
    className,
  );

  const mergedStyle: CSSProperties = {
    ...style,
    backgroundColor: color ?? (style as CSSProperties | undefined)?.backgroundColor,
  };

  return (
    <span ref={ref} className={classes} style={mergedStyle} onClick={onClick} {...rest}>
      <span className={ns.e('content')}>{children}</span>
      {closable && (
        <button
          type="button"
          className={ns.e('close')}
          aria-label="Close"
          onClick={(e) => {
            e.stopPropagation();
            onClose?.(e);
          }}
        >
          <svg viewBox="0 0 24 24" width="1em" height="1em" aria-hidden="true">
            <path
              fill="currentColor"
              d="M12 10.586 6.707 5.293a1 1 0 0 0-1.414 1.414L10.586 12l-5.293 5.293a1 1 0 1 0 1.414 1.414L12 13.414l5.293 5.293a1 1 0 0 0 1.414-1.414L13.414 12l5.293-5.293a1 1 0 0 0-1.414-1.414L12 10.586Z"
            />
          </svg>
        </button>
      )}
    </span>
  );
});

.ec-tag {
  --ec-tag-bg-color: var(--ec-color-primary-light-9);
  --ec-tag-text-color: var(--ec-color-primary);
  --ec-tag-border-color: var(--ec-color-primary-light-8);
  --ec-tag-hover-color: var(--ec-color-primary);
  --ec-tag-size: 24px;
  --ec-tag-font-size: var(--ec-font-size-small);
  --ec-tag-padding-horizontal: 9px;
  --ec-tag-border-radius: var(--ec-border-radius-base);

  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  gap: 6px;
  height: var(--ec-tag-size);
  padding: 0 var(--ec-tag-padding-horizontal);
  font-family: inherit;
  font-size: var(--ec-tag-font-size);
  line-height: 1;
  white-space: nowrap;
  color: var(--ec-tag-text-color);
  background-color: var(--ec-tag-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-tag-border-color);
  border-radius: var(--ec-tag-border-radius);
  transition: var(--ec-transition-all);
}

.ec-tag__content {
  display: inline-flex;
  align-items: center;
}

.ec-tag__close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: 14px;
  height: 14px;
  padding: 0;
  margin: 0;
  font-size: 12px;
  color: inherit;
  cursor: pointer;
  background-color: transparent;
  border: none;
  border-radius: var(--ec-border-radius-circle);
  outline: none;
  transition: var(--ec-transition-all);
}

.ec-tag__close:hover {
  color: var(--ec-color-white);
  background-color: var(--ec-tag-hover-color);
}

.ec-tag__close:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

/* ---- Modifiers ---- */
.ec-tag.is-disable-transitions,
.ec-tag.is-disable-transitions .ec-tag__close {
  transition: none;
}

.ec-tag.is-round {
  --ec-tag-border-radius: var(--ec-border-radius-round);
}

.ec-tag.is-hit {
  border-color: var(--ec-tag-text-color);
}

/* ---- Sizes ---- */
.ec-tag--large {
  --ec-tag-size: 32px;
  --ec-tag-font-size: var(--ec-font-size-base);
  --ec-tag-padding-horizontal: 11px;
}

.ec-tag--small {
  --ec-tag-size: 20px;
  --ec-tag-padding-horizontal: 7px;
}

.ec-tag--small .ec-tag__close {
  width: 12px;
  height: 12px;
  font-size: 10px;
}

/* =========================================================
   Light effect (default): light-9 bg + accessible text + light-8 border

   The brand base color (e.g. var(--ec-color-success)) does not reach the
   WCAG 2.1 AA 4.5:1 contrast ratio against its own light-9 background, and
   neither does dark-2. The component-scoped text tokens below are computed
   as mix(black, base, 0.4) (i.e. base channels * 0.4) and clear 4.5:1 on the
   corresponding light-9 background for every type (range 5.13:1 to 6.48:1).
   ========================================================= */
.ec-tag--light {
  --ec-tag-light-text-primary: #265f99;
  --ec-tag-light-text-success: #3e7423;
  --ec-tag-light-text-info: #56585c;
  --ec-tag-light-text-warning: #8a6124;
  --ec-tag-light-text-danger: #934141;
}
.ec-tag--primary.ec-tag--light {
  --ec-tag-bg-color: var(--ec-color-primary-light-9);
  --ec-tag-text-color: var(--ec-tag-light-text-primary);
  --ec-tag-border-color: var(--ec-color-primary-light-8);
  --ec-tag-hover-color: var(--ec-color-primary);
}
.ec-tag--success.ec-tag--light {
  --ec-tag-bg-color: var(--ec-color-success-light-9);
  --ec-tag-text-color: var(--ec-tag-light-text-success);
  --ec-tag-border-color: var(--ec-color-success-light-8);
  --ec-tag-hover-color: var(--ec-color-success);
}
.ec-tag--info.ec-tag--light {
  --ec-tag-bg-color: var(--ec-color-info-light-9);
  --ec-tag-text-color: var(--ec-tag-light-text-info);
  --ec-tag-border-color: var(--ec-color-info-light-8);
  --ec-tag-hover-color: var(--ec-color-info);
}
.ec-tag--warning.ec-tag--light {
  --ec-tag-bg-color: var(--ec-color-warning-light-9);
  --ec-tag-text-color: var(--ec-tag-light-text-warning);
  --ec-tag-border-color: var(--ec-color-warning-light-8);
  --ec-tag-hover-color: var(--ec-color-warning);
}
.ec-tag--danger.ec-tag--light {
  --ec-tag-bg-color: var(--ec-color-danger-light-9);
  --ec-tag-text-color: var(--ec-tag-light-text-danger);
  --ec-tag-border-color: var(--ec-color-danger-light-8);
  --ec-tag-hover-color: var(--ec-color-danger);
}

/* =========================================================
   Dark effect: solid color bg + white text
   ========================================================= */
.ec-tag--primary.ec-tag--dark {
  --ec-tag-bg-color: var(--ec-color-primary);
  --ec-tag-text-color: var(--ec-color-primary-contrast);
  --ec-tag-border-color: var(--ec-color-primary);
  --ec-tag-hover-color: var(--ec-color-primary-light-3);
}
.ec-tag--success.ec-tag--dark {
  --ec-tag-bg-color: var(--ec-color-success);
  --ec-tag-text-color: var(--ec-color-success-contrast);
  --ec-tag-border-color: var(--ec-color-success);
  --ec-tag-hover-color: var(--ec-color-success-light-3);
}
.ec-tag--info.ec-tag--dark {
  --ec-tag-bg-color: var(--ec-color-info);
  --ec-tag-text-color: var(--ec-color-info-contrast);
  --ec-tag-border-color: var(--ec-color-info);
  --ec-tag-hover-color: var(--ec-color-info-light-3);
}
.ec-tag--warning.ec-tag--dark {
  --ec-tag-bg-color: var(--ec-color-warning);
  --ec-tag-text-color: var(--ec-color-warning-contrast);
  --ec-tag-border-color: var(--ec-color-warning);
  --ec-tag-hover-color: var(--ec-color-warning-light-3);
}
.ec-tag--danger.ec-tag--dark {
  --ec-tag-bg-color: var(--ec-color-danger);
  --ec-tag-text-color: var(--ec-color-danger-contrast);
  --ec-tag-border-color: var(--ec-color-danger);
  --ec-tag-hover-color: var(--ec-color-danger-light-3);
}

/* =========================================================
   Plain effect: transparent bg + color text + light-5 border
   ========================================================= */
.ec-tag--primary.ec-tag--plain {
  --ec-tag-bg-color: var(--ec-fill-color-blank);
  --ec-tag-text-color: var(--ec-color-primary);
  --ec-tag-border-color: var(--ec-color-primary-light-5);
  --ec-tag-hover-color: var(--ec-color-primary);
}
.ec-tag--success.ec-tag--plain {
  --ec-tag-bg-color: var(--ec-fill-color-blank);
  --ec-tag-text-color: var(--ec-color-success);
  --ec-tag-border-color: var(--ec-color-success-light-5);
  --ec-tag-hover-color: var(--ec-color-success);
}
.ec-tag--info.ec-tag--plain {
  --ec-tag-bg-color: var(--ec-fill-color-blank);
  --ec-tag-text-color: var(--ec-color-info);
  --ec-tag-border-color: var(--ec-color-info-light-5);
  --ec-tag-hover-color: var(--ec-color-info);
}
.ec-tag--warning.ec-tag--plain {
  --ec-tag-bg-color: var(--ec-fill-color-blank);
  --ec-tag-text-color: var(--ec-color-warning);
  --ec-tag-border-color: var(--ec-color-warning-light-5);
  --ec-tag-hover-color: var(--ec-color-warning);
}
.ec-tag--danger.ec-tag--plain {
  --ec-tag-bg-color: var(--ec-fill-color-blank);
  --ec-tag-text-color: var(--ec-color-danger);
  --ec-tag-border-color: var(--ec-color-danger-light-5);
  --ec-tag-hover-color: var(--ec-color-danger);
}
